function makeRng(baseSeed, entityId, tag, tsMs) {
    const key = String(baseSeed) + ':' + String(entityId) + ':' + String(tag) + ':' + String(tsMs);
    const seedHex = crypto.createHash('sha256').update(key).digest('hex').slice(0, 16);
    return seedrandom.alea(seedHex);
}
function uniform(rng, min, max) { return min + (max - min) * rng(); }
function normal(rng, mean, stddev) {
    let u = 0; let v = 0;
    while (u === 0) u = rng();
    while (v === 0) v = rng();
    const z = Math.sqrt(-2 * Math.log(u)) * Math.cos(2 * Math.PI * v);
    return mean + stddev * z;
}
function isWeekend(d) { const w = d.getUTCDay(); return w === 0 || w === 6; }

const DEFAULT_CFG = {
    device_id: 'device-default',
    device_type: 'industrial_oven',
    rated_power_kw: 3.0,
    duty_cycle_pct: 70.0,
    power_variance_pct: 5.0,
    operate_on_weekends: false,
    operating_windows: [{ start_hour: 6, end_hour: 18 }]
};

function inWindow(hour, windows) {
    for (const w of windows) {
        if (w.start_hour <= w.end_hour) {
            if (hour >= w.start_hour && hour < w.end_hour) return true;
        } else {
            // Overnight wrap
            if (hour >= w.start_hour || hour < w.end_hour) return true;
        }
    }
    return false;
}

function shouldOperate(date, cfg) {
    if (isWeekend(date) && !cfg.operate_on_weekends) return false;
    return inWindow(date.getUTCHours(), cfg.operating_windows);
}

function generateConsumer(payload) {
    const baseSeed = (typeof payload.base_seed === 'number') ? payload.base_seed : 12345;
    const entityId = payload.entity_id || 'device-default';
    const tsMs = (typeof payload.timestamp_ms === 'number') ? payload.timestamp_ms : 0;
    const isoTs = payload.timestamp || new Date(tsMs).toISOString();
    const siteId = payload.site_id || '';
    const cfg = Object.assign({}, DEFAULT_CFG, payload.config || {});
    const mode = payload.mode || 'normal';
    const date = new Date(isoTs);
    const rng = makeRng(baseSeed, entityId, 'consumer', tsMs);

    let state = 'OFF';
    if (shouldOperate(date, cfg)) {
        const dutyFrac = cfg.duty_cycle_pct / 100;
        if (rng() < dutyFrac) state = 'ON';
    }
    if (mode === 'event') {
        const minOfDay = date.getUTCHours() * 60 + date.getUTCMinutes();
        if (minOfDay >= 1020 && minOfDay < 1140) state = 'ON';
    }

    let power = 0;
    if (state === 'ON') {
        const variance = cfg.rated_power_kw * (cfg.power_variance_pct / 100);
        const noise = uniform(rng, -variance, variance);
        power = Math.max(0, cfg.rated_power_kw + noise);
    }

    return {
        site_id: siteId,
        timestamp: isoTs,
        device_id: cfg.device_id || entityId,
        device_type: cfg.device_type,
        device_state: state,
        device_power_kw: power
    };
}

msg.payload = generateConsumer(msg.payload || {});
return msg;
